# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
app = Flask(__name__)

# Template for welcome page
template = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Welcome {{ name }}!</title>
    <style>
        body { font-family: Arial, sans-serif; }
        h2 { color: #00698f; }
        p { margin-bottom: 20px; }
        .bio { font-style: italic; }
        .status { font-weight: bold; }
    </style>
</head>
<body>
    <h1>Welcome {{ name }}!</h1>
    <p>Location: {{ location }}</p>
    <div class="bio">{{ bio | safe }}</div>
    <div class="status">{{ status | safe }}</div>
</body>
</html>
"""

@app.route('/welcome')
def welcome():
    name = request.args.get('name', default='', type=str)
    bio = request.args.get('bio', default='', type=str)
    location = request.args.get('location', default='', type=str)
    status = request.args.get('status', default='', type=str)

    # Basic formatting support
    if '***' in bio:
        bio = bio.replace('***', '<b>', 1).replace('***', '</b>', 1)
    if '__' in bio:
        bio = bio.replace('__', '<i>', 1).replace('__', '</i>', 1)

    if '***' in status:
        status = status.replace('***', '<b>', 1).replace('***', '</b>', 1)
    if '__' in status:
        status = status.replace('__', '<i>', 1).replace('__', '</i>', 1)

    rendered_template = render_template_string(template, name=name, bio=bio, location=location, status=status)
    return rendered_template

if __name__ == "__main__":
    app.run(debug=True)